var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……그래서, 백작가문에 데릴사위로 들어가기로 했다?","JPN":"……それで、伯爵家の入り婿になったと？","ENG":"...So you're saying you're marrying into the Birmingham family?","TWN":"……所以，你決定入贅伯爵家了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 어쩌다 보니 그렇게 됐군요.","JPN":"はい。成り行きでそうなりました。","ENG":"Yes. It just sort of happened that way.","TWN":"是的，事情就變成這樣了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"어쩌다는 무슨. 대체 무슨 짓을 하면 양이나 치던 놈이 백작가의 후계자를 꼬셔?","JPN":"成り行きなわけないだろう。いったいどうやって羊飼いが伯爵家の後継者を口説いたんだ？","ENG":"Just happened? What on earth did you pull to make the Count's heir fall for a shepherd?","TWN":"你少來。到底要做什麼才能讓一個放羊的傢伙勾引到伯爵家的繼承人？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L7_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"거기에, 뭐? 구원기사단의 단장이 됐다고? 지금 나보고 그 말을 믿으라는 거냐?","JPN":"それに、何だ？　救世騎士団の団長になった？　それを信じろというのか？","ENG":"And what's this about becoming the captain of the Knights of Redemption? You expect me to believe that?","TWN":"你說什麼？你說你現在是救贖騎士團的團長？鬼才相信。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제국의 황태자 전하께서는 능력 위주로 사람을 인선하십니다.","JPN":"帝国の皇太子殿下は能力で人をお選びになります。","ENG":"His Highness, the Crown Prince, selects people based on ability.","TWN":"帝國的皇太子殿下是以能力為主來選拔人才的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"평민 출신의 기사도 여럿 있으니, 양치기 출신이 기사단의 단장이어도 이상함은 없죠.","JPN":"平民出身の騎士も数人いますので、羊飼い出身が騎士団の団長だとしてもおかしくはないんです。","ENG":"There are several knights of common birth, so it's not strange for a former shepherd to become a captain.","TWN":"既然有不少平民出身的騎士，那麼牧羊人出身的騎士團團長也沒有什麼奇怪的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……허어, 어렸을 때부터 크게 될 놈이라고는 생각했지만 설마 이정도로 출세할 줄이야.","JPN":"ほう、小さい頃から大物になるとは思っていたんだが、ここまで出世するとはな。","ENG":"Huh. I always knew you'd do well, but I didn't think you'd go this far.","TWN":"……哈，我從小就覺得你這傢伙會有出息，但沒想到會出人頭地到這種程度。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그럼 결혼식은 언제 올릴 생각이냐?","JPN":"じゃあ、結婚式はいつ挙げるんだ？","ENG":"So, when's the wedding?","TWN":"那麼你打算什麼時候舉行婚禮呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전시 상황인 만큼 둘이서 간단하게 식을 치르기로 했습니다.","JPN":"戦時なので、2人だけで簡単に挙げることにしました。","ENG":"Given the wartime situation, we've decided to hold a small private ceremony.","TWN":"由於是戰爭期間，我們決定簡單地舉行儀式。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 출신이 출신인 만큼, 아내가 배려해 준 것이겠죠.","JPN":"私の出身もありますので、妻が配慮してくれたのでしょう。","ENG":"It's probably her way of being considerate, knowing my background.","TWN":"因為我的出身，妻子才會如此體貼吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……넌 진짜 아내한테 잘해라.","JPN":"……奥さんによくしてやれよ。","ENG":"...You'd better treat her well.","TWN":"……你可要對你妻子好一點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말씀처럼 그럴 생각입니다.","JPN":"はい、そのつもりです。","ENG":"I intend to. Just as you said.","TWN":"我也是這麼想的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그런데 청첩장 돌리러 온 것도 아니면 마을에는 왜 돌아온 게냐?","JPN":"で、招待状を配るわけでもないのに、村にはどうして帰ってきたんだ？","ENG":"So if you're not here to hand out wedding invitations, why'd you come back to the village?","TWN":"那麼，如果不是來發請帖的話，為什麼要回到村子裡呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"소식을 전하기 위함도 있지만, 다른 용건들도 있습니다.","JPN":"近況を知らせるためでもありますが、他に用事がありまして。","ENG":"Partly to share the news, but I had other reasons, too.","TWN":"雖然是為了傳達消息，但也有其他事情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아내가 마을에 오기를 원했기도 하고…….","JPN":"妻が村に来たいと言っていたのもありますし……","ENG":"My wife wanted to visit the village, and...","TWN":"妻子也希望能來村子……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"만나야 할 사람이 한 명 더 있으니까요.","JPN":"会うべき人がもう一人いますから。","ENG":"There's one more person I need to see.","TWN":"因為還有一個人我們必須見。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그래. 그랬었지, 참.","JPN":"ああ。そうだったな、そういえば。","ENG":"Right, I almost forgot.","TWN":"對，沒錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그녀석이라면 평소처럼 말을 돌보고 있을 테니, 그리로 가보거라.","JPN":"あいつならいつもどおり馬の世話をしているはずだ。そこに行ってみろ。","ENG":"If it's him, he's probably tending the horses as usual. You should head that way.","TWN":"如果是那傢伙的話，應該像平時一樣在照看馬匹，去那裡看看吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 감사합니다, 숙부님.","JPN":"はい。ありがとうございます、叔父さん。","ENG":"Thank you, Uncle.","TWN":"好的，謝謝你，叔叔。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"영주님네 마구간에서 조금 걸으면, 어릴 적 울타리를 넘은 말이 남긴 말발굽 자국이 있지.","JPN":"領主の馬小屋からもう少し歩くと、幼い頃柵を越えた馬が残したひづめの跡がある。","ENG":"Just past the stables, there's a spot where a horse once jumped the fence and left hoofprints.","TWN":"在領主家的馬廄走一會兒，就能看到小時候越過圍欄的馬留下的馬蹄印。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 길을 따라 쭉 걷다 보면, 마을 중심에 있는 나무 앞에 도착하고.","JPN":"その道に沿って歩いていくと、村の中心にある木の前にたどり着いて。","ENG":"If you follow that trail, it leads to the big tree at the village center.","TWN":"沿著那條路一直走，就會到達村莊中心的那棵樹前。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 거기가 늘 알렌과의 대련 장소였지.","JPN":"そして、そこがいつもアレンと立ち合い稽古してたところだったよね。","ENG":"That was always the spot where Allen and I used to spar.","TWN":"而且那裡一直是和艾倫對練的地方。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그립네. 어렸을 적에는 늘 그러고 놀았는데.","JPN":"懐かしいな。小さい時はいつもそうやって遊んでたのに。","ENG":"I miss those days. We used to play like that all the time.","TWN":"懷念啊。小時候總是這樣玩。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"여전하군.","JPN":"相変わらずだな。","ENG":"Still the same, I see.","TWN":"依舊如故。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"약속하지도 않았는데 이리 만난 걸 보면, 너랑은 인연이 있는 걸지도 모르겠어.","JPN":"約束もしていないのにこうやって出会うのは、君とは絆があるのかもしれない。","ENG":"Funny how we keep running into each other without even making plans. Maybe it's fate.","TWN":"雖然沒有約定，但能在這裡遇見你，或許我們之間有緣分吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그러게. 나도 어쩐지 그런 기분이 들었어.","JPN":"そうだね。僕もなんとなくそんな気がしてたよ。","ENG":"Yeah. I was just thinking the same thing.","TWN":"是啊，我也莫名有這種感覺。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"오랜만이야, 알렌. 센트럴 팰리스에서의 생활은 어때?","JPN":"久しぶり、アレン。セントラルパレスでの生活はどう？","ENG":"It's been a while, Allen. How's life at Central Palace?","TWN":"好久不見，艾倫。在聖特羅貝里斯的生活怎麼樣？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"나 결혼한다.","JPN":"結婚することになった。","ENG":"I'm getting married.","TWN":"我要結婚了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그렇구나. 상대는 역시 예전에 마을에 오신 그 영애 분?","JPN":"そうなんだ。相手はやっぱり、昔に村に来たあの令嬢の方？","ENG":"I see. To that noble lady who came to the village before, right?","TWN":"是嗎。對方是以前來過村子的那位小姐嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"의외의 반응이군. 놀랍지 않은 건가?","JPN":"意外な反応だな。驚かないのか？","ENG":"Not surprised?","TWN":"意外的反應啊。你不覺得驚訝嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너라면 분명 말이라도 절 줄 알았는데.","JPN":"君ならきっと言い淀むと思っていたのだが。","ENG":"I figured you'd at least stutter.","TWN":"我就知道你至少會說些什麼。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"음… 사실 마을에 있을 때부터 둘이 좋은 분위기라는 걸 어렴풋이 눈치챘거든.","JPN":"うーん……実は村にいた時から、2人の良い雰囲気にはなんとなく気づいていたからね。","ENG":"Well... I kind of sensed something between you two back then.","TWN":"嗯……其實在村子裡的時候，我就隱約察覺到你們兩個關係不錯了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"둘이 같이 있을 수 있도록 의도적으로 피해 다녔는데, 눈치 못 챘어?","JPN":"2人きりになれるようにわざと避けてたんだけど、知らなかった？","ENG":"I even tried to avoid you so you could be with her, undisturbed. Didn't you notice?","TWN":"我故意避開你們，讓你們能單獨相處，你沒察覺嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"설마. 난 네가 귀족과 있는 게 불편해서 그런 줄 알았다.","JPN":"まさか。私は君が貴族と一緒にいるのが気まずくてそうしているんだと思っていた。","ENG":"Honestly, I thought you were just uncomfortable being around nobles.","TWN":"不會吧。我還以為你是因為和貴族在一起不舒服才這樣的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"말은 안 해도 알렌한테서 제법 티가 났으니까.","JPN":"口には出さないけど、アレンって結構わかりやすいんだよ。","ENG":"You didn't say anything, but it was obvious.","TWN":"雖然沒說，但從艾倫身上還是能看出來的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"포기했던 제도행까지 다시 마음먹었으니 분명 평범한 마음은 아니었겠지.","JPN":"諦めてた帝都にも戻る決意をするくらいだし、きっと軽い気持ちじゃないんだろうって。","ENG":"You even changed your mind about leaving for the capital. You wouldn't do that without strong feelings.","TWN":"原本已經放棄首都的生活，現在又重新決定要前往首都，心情應該蠻複雜的吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"넌, 남의 일에는 눈치가 빠르군.","JPN":"君は、他人のことに関しては察しがいいな。","ENG":"You're oddly perceptive about other people.","TWN":"你對別人的事情倒是很敏銳啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"응…? 남의 일이라니?","JPN":"うん……？　他人のことって？","ENG":"Huh...? What do you mean \\"other people\\"?","TWN":"嗯……？別人的事？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아무것도 아니다.","JPN":"何でもない。","ENG":"It's nothing.","TWN":"沒什麼。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그저 먼 미래에 널 좋아하게 될 여성이 안쓰러웠을 뿐이야.","JPN":"ただ、遠い未来に君を好きになる女性が可哀想だと思っただけだ。","ENG":"I just feel bad for the girl who might fall for you someday.","TWN":"只是覺得將來喜歡上你的女生有些可憐罷了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그, 그 정도로 내가 별로야?","JPN":"ぼ、僕ってそこまで頼りない？","ENG":"W-what? Am I that bad?","TWN":"我，我真的那麼差勁嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그래도 다행이다.","JPN":"でも、よかった。","ENG":"Still, I'm glad.","TWN":"但我還是覺得很替你高興。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"표정이 밝은 걸 보면 알렌은 나랑 다르게 도시생활이 체질에 맞나 봐.","JPN":"顔が明るいし、アレンは僕とは違って都市での生活が合ってるみたいだ。","ENG":"You look happy, Allen. I guess you were meant for city life after all.","TWN":"看你的表情這麼明亮，看來艾倫和我不一樣，適合城市生活呢。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 솔직히 쉽지는 않아.","JPN":"いや、正直簡単ではない。","ENG":"Not really. It's been tough, honestly.","TWN":"不，老實說不會那麼簡單。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"귀족의 예법이나 복잡한 정치. 하다못해 걸음걸이에도 신경 써야 하는 자리거든.","JPN":"貴族の作法や複雑な政治。歩き方まで気をつけないといけない位置なんだ。","ENG":"Noble etiquette and politics. Even how you walk matters in that world.","TWN":"貴族的禮儀或複雜的政治。甚至連走路的姿勢都要注意的場合。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"무엇보다 평화랑은 거리가 먼 전시 상황이고.","JPN":"なにより平和とは程遠い戦時だからな。","ENG":"And we're in the middle of a war, so peace is a distant dream.","TWN":"最重要的是，這是一種與和平相距甚遠的戰時狀態。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이. 나와 같이 수도로 가자. 아르카데나 제국에는 네 힘이 필요해.","JPN":"レイ。私と一緒に首都へ行こう。アルカデナ帝国には君の力が必要だ。","ENG":"Ray. Come to the capital with me. The Empire of Arcadena needs your strength.","TWN":"雷伊，跟我一起去首都。艾爾卡特納帝國需要你的力量。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"언젠가 다가올 마왕과의 싸움에서 네 힘은 큰 도움이 될 거야.","JPN":"いつかやってくる魔王との戦いで、君の力は大きな助けとなるはずだ。","ENG":"When we face the Demon Lord someday, your aid will make a difference.","TWN":"在未來與魔王的戰鬥中，你的力量將是巨大的幫助。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"미안, 알렌. 난 알렌이 생각하는 것만큼 강하지 않아.","JPN":"ごめん、アレン。僕はアレンが思ってるほど強くないんだ。","ENG":"Sorry, Allen. I'm not as strong as you think I am.","TWN":"對不起，艾倫。我並不是你想像中的那種了不起的人。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래. 그렇다면 어쩔 수 없지.","JPN":"そうか。なら仕方ない。","ENG":"I see. Then I won't push it.","TWN":"是啊，那就沒辦法了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"응? 괜찮아?","JPN":"え？　いいの？","ENG":"Huh? You're okay with that?","TWN":"嗯？沒關係嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이번 건 권유였을 뿐이야. 남의 등을 억지로 떠민다는 게 잔혹한 짓이라는 건 알고 있다.","JPN":"今回はただの勧誘だ。無理やり人の背中を押すことが残酷な行為だということはわかっている。","ENG":"It was just an offer. I know how cruel it is to shove someone forward against their will.","TWN":"這次只是建議而已。我知道強迫別人做事是殘酷的行為。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"만약 그런 상황이 온다면 세상에 죽음이 만연한 절망적인 상황이라는 뜻이겠지만…….","JPN":"もしそのような状況が来たら、世界に死が蔓延している絶望的な状況だという意味だろうが……","ENG":"If that time ever comes, it'll mean the world is already in a dire state...","TWN":"如果出現那種情況，那就意味著世界陷入了死亡彌漫的絕望境地……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그런 세상이 오지 않도록 하는 게 기사단의 역할이야.","JPN":"そんな世界にならないようにするのが騎士団の役割だ。","ENG":"And our job as knights is to make sure that future never happens.","TWN":"防止那樣的世界到來是騎士團的職責。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"결혼 소식을 전하러 온 김에 겸사로 해본 이야기일 뿐이니, 너무 신경 쓸 필요는 없다.","JPN":"結婚を知らせるために来たついでに話してみただけだ。あまり気にする必要はない。","ENG":"I brought it up while sharing my wedding news, that's all. Don't worry too much about it.","TWN":"只是順便來傳達結婚消息時順便說說而已，不用太在意。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"……알렌은 강하구나.","JPN":"……アレンは強いんだね。","ENG":"...You're strong, Allen.","TWN":"……艾倫很強啊。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"설마. 버팀목에 기대 겨우 버티고 있을 뿐이다.","JPN":"まさか。支えのおかげで何とか耐えているだけだ。","ENG":"Not really. I'm just leaning on someone else to stay standing.","TWN":"怎麼可能。我只是靠著支柱勉強撐著而已。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"으응, 아냐. 알렌이 해준 말 덕분에 마음이 편해졌는걸?","JPN":"ううん、強いよ。僕はアレンの言葉のおかげで、心が楽になったんだよ？","ENG":"Still, your words helped. I feel a lot better now.","TWN":"嗯，不是。因為艾倫說的話讓我心情好多了呢？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그러니 보답이라고 하긴 뭐하지만… 전쟁 중에 문제가 생기더라도 너무 걱정 마.","JPN":"だから、戦争中に何か問題が起きてもあんまり心配しないで。","ENG":"So even if something happens during the war, don't worry too much.","TWN":"所以雖然不算是回報……但即使在戰爭中出現問題，也不要太擔心。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그런 일이 생긴다면, 둘의 아이는 내가 반드시 지켜줄게.","JPN":"そんなことがあったら、ふたりの子どもは僕が必ず守ってあげる。","ENG":"If it comes to it, I'll protect your child.","TWN":"如果發生那種事，我一定會保護你們的孩子。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"물론 내가 아니더라도 백작령의 기사분들이 계시니 큰 문제는 없을 테지만.","JPN":"もちろん、僕じゃなくても伯爵領の騎士たちがいるから問題はないだろうけどね。","ENG":"Of course, even if it's not me, the knights of the County will keep them safe.","TWN":"當然，即使沒有我，伯爵領地的騎士們也在，所以不會有大問題。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……당연한 말이지만 손을 잡는다고 아이가 생기진 않아.","JPN":"……当たり前のことだが、手を繋ぐだけでは子どもは生まれないぞ。","ENG":"...Just to be clear, holding hands doesn't make babies.","TWN":"……雖然是理所當然的話，但光牽手並不會有孩子。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"나, 나도 그 정도는 안다고?","JPN":"ぼ、僕だってそのくらいは知ってる！","ENG":"I-I know that much!","TWN":"我，我知道好嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이. 괜찮다면 오랜만에 대련해보지 않겠나?","JPN":"レイ。よかったら久しぶりに稽古してみないか？","ENG":"Ray. Would you like to spar again? It's been a while.","TWN":"雷伊，如果可以的話，要不要久違地切磋一下？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L35_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"갑자기…? 아내분이 기다리고 계신 거 아니야?","JPN":"いきなり……？　奥さんが待ってるんじゃない？","ENG":"Right now...? Shouldn't your wife be waiting?","TWN":"突然……？不是妻子在等你嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아직 그 정도의 시간은 있다.","JPN":"まだそれくらいの時間はある。","ENG":"We've still got some time.","TWN":"還是有點時間的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 지금이라면, 이제와는 다른 결과를 낼 수 있을 것만 같은 기분이 들어서 말이야.","JPN":"それに今なら、これまでとは違う結果を出せるような気がしてな。","ENG":"And I feel like I might be able to change the outcome this time.","TWN":"而且現在，我有種感覺，似乎能取得與過去不同的結果。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"응. 알았어.","JPN":"うん。わかった。","ENG":"All right.","TWN":"嗯，知道了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"대련하자, 알렌.","JPN":"稽古しよう、アレン。","ENG":"Let's do it, Allen.","TWN":"來切磋吧，艾倫。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"풉… 푸흡… 푸흐흐…….","JPN":"ぷっ……ぷふっ……うふふ……","ENG":"Pff... Pfft... Pfff...","TWN":"噗……噗噗……噗哈哈……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"푸흡… 푸흐흐… 큭, 크흡…….","JPN":"ぷふっ……ふふふ……ぐふっ、ふふっ……","ENG":"Pfft... Pff... Kgh– Pfft...","TWN":"噗……噗呵呵……咳，咳……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"차라리 대놓고 웃게. 애써 참으려는 모습이 더 비참하니.","JPN":"どうせなら大声で笑ってくれ。笑いを堪えてる姿を見る方がもっと悲惨だ。","ENG":"You might as well laugh out loud. Watching you try to hold it in is even sadder.","TWN":"倒不如直接笑出來。努力忍住的樣子更難看。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"푸하하하! 참 잘하셨습니다! 이래야, 이래야 구원기사단의 단장이지요!!","JPN":"あははは！　それはもうよくやりましたね！　それが、それでこそ救世騎士団の団長です！！","ENG":"HAHAHAHA! Brilliantly done! Now that's a proper captain of the Knights of Redemption!","TWN":"哈哈哈！幹得好！這才是，這才是救贖騎士團的團長啊！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"설마 한 대도… 크흡…! 한 대도 못 맞출 줄은…!!","JPN":"まさか一回も……ぐふっ……！　一回も攻撃を当てられなかったなんて……！！","ENG":"To think you... Pfft...! Couldn't even land a single hit...!!","TWN":"難道一發都……呃……！居然一發都沒打中……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"내가 약한 게 아니야. 그 녀석이 이상한 거다.","JPN":"私が弱いわけではない。あいつが変なのだ。","ENG":"I'm not weak. He's just weird.","TWN":"不是我弱，是那傢伙太奇怪了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 그럼에도 용감하게 맞서 싸운… 크흡. 제 남편이 참으로 자랑스럽네요.","JPN":"ええ。それでも勇敢に戦った……ぷふっ。私の夫がとても誇らしいです。","ENG":"Even so, I'm proud of you for... facing him bravely, pfft. My dear husband.","TWN":"是的。即便如此，他依然勇敢地迎戰……呵，我丈夫真是讓我感到驕傲啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 그런 호구 같은 점도 좋아하니 너무 자책하실 필요 없습니다.","JPN":"私はそういう間抜けなところも好きなので、あまり自分を責めないでくださいね。","ENG":"And I happen to like that hopeless side of you, so don't beat yourself up.","TWN":"我喜歡你那傻乎乎的一面，所以不用太自責。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"호, 호구……?","JPN":"ま、間抜け……？","ENG":"H-hopeless...?","TWN":"傻，傻乎乎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그래도 레이가 손대중을 해서 다행입니다.","JPN":"それでも、レイが手加減をしてくれて何よりです。","ENG":"Still, good thing Ray held back.","TWN":"不過幸好雷伊有控制住力度。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"백작가의 귀중한 자산에 상처라도 났다간 제 화가 머리끝까지 났을 거예요.","JPN":"伯爵家の貴重な財産に傷でもついたら、私が怒ったはずですもの。","ENG":"If the Count's precious asset got injured, I'd have been absolutely furious.","TWN":"伯爵家的珍貴資產若是受了傷，我會生氣的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"편을 들어주는 건지, 놀리는 건지 모르겠군.","JPN":"味方してくれているのか、からかっているのか、わからないな。","ENG":"Are you supporting me or mocking me?","TWN":"不知道你是在幫我，還是在嘲笑我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 제가 언제 당신 편이 아닌 적이 있었나요?","JPN":"まあ。私が貴方の味方でなかった時がありましたか？","ENG":"Oh dear. Have I ever not been on your side?","TWN":"哎呀。我什麼時候不站在你這邊了呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"한 번 있었지. 백작님에게 약혼 사실을 보고하러 갔을 때.","JPN":"一度あった。伯爵に婚約のご報告にあがった時。","ENG":"There was that one time. When we went to tell your father we were engaged.","TWN":"有一次，當我去向伯爵報告訂婚的事情時。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"백작가의 귀중한 외동딸에 손을 댔으니 천하의 도둑놈은 맞지 않습니까?","JPN":"伯爵家の大事な一人娘に手を出したのですよ。天下の大盗賊で合っているのでは？","ENG":"You did lay hands on the Count's precious only daughter. That makes you quite the scoundrel, doesn't it?","TWN":"動了伯爵家的寶貴獨生女，不就是十惡不赦的混蛋嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"따귀를 맞는 것만큼은 막아드렸으니, 이 아내의 자비에 평생 감사하세요.","JPN":"頬を叩かれることだけは止めてさしあげたのですから、この妻の慈悲に感謝してください。","ENG":"Be grateful I stopped him from slapping you. You'll owe your merciful wife forever.","TWN":"至少我幫你擋下了耳光，你要一輩子感謝我這位仁慈的妻子吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래서, 마을은 잘 둘러보았나?","JPN":"それで、村は見て回れたのか？","ENG":"So, did you get to see the village?","TWN":"所以，村子都逛遍了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 적당히 남는 시간 동안 둘러보았습니다.","JPN":"ええ。残りの時間に適当に見回りました。","ENG":"Yes. I wandered around a bit when I had time.","TWN":"是的。我在剩餘的時間裡稍微看了一下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"적당히라니. 마을을 둘러보고 싶어서 온 게 아니었나?","JPN":"適当に？　村を見たくて来たわけではなかったのか？","ENG":"\\"A bit\\"? I thought seeing the village was your whole reason for coming.","TWN":"適可而止。不是說想環顧一下村子才來的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것도 틀린 말은 아니지만… 그냥, 이곳에 오면 마음이 편해서요.","JPN":"間違ってはいませんが……ただ、ここに来ると気が楽になるのです。","ENG":"That's not entirely wrong... But honestly, I just feel at peace here.","TWN":"雖然這麼說也沒錯……只是，來到這裡讓我感到安心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전쟁이 끝나면 은퇴한 후에 이곳에서 사는 것도 나쁘지 않을 것 같습니다.","JPN":"戦争が終わったら、引退してここで暮らすのも悪くなさそうです。","ENG":"Once the war ends, I think this would be a lovely place to retire.","TWN":"戰爭結束後，退休後住在這裡也不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하께서 제국의 참모와 기사단장을 쉬이 놓아주실지는 모르겠군.","JPN":"殿下が帝国の参謀と騎士団長を簡単に手放してくださるかはわからないがな。","ENG":"Not sure the His Majesty would be willing to let go of both a top strategist and the knight captain.","TWN":"殿下是否會輕易放過帝國的參謀和騎士團長，我還不確定"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"안되면 몰래 도망칠까요?","JPN":"駄目なら、こっそり逃げましょうか？","ENG":"Then we'll just sneak off.","TWN":"不行的話，要不要偷偷逃走？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"당신이 좋다면 그것도 괜찮겠지.","JPN":"君がそれでいいなら、構わない。","ENG":"If that's what you want, I'm all for it.","TWN":"如果你覺得好，那也不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……무리하지 말게, 그레이스.","JPN":"……無理するな、グレース。","ENG":"...Don't push yourself too hard, Grace.","TWN":"……別勉強自己，葛瑞絲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"연속된 패전은 그대의 잘못이 아니야.","JPN":"立てつづけの敗戦は君のせいではない。","ENG":"The recent losses weren't your fault.","TWN":"連續的敗戰不是你的錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"잘못은 없더라도 책임은 있는 법이지요.","JPN":"私のせいでなくても、責任はあります。","ENG":"Even if they weren't, I'm still responsible.","TWN":"即使沒有過錯，也要承擔責任。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 책임감이 자네를 짓누르는 게 느껴져서 하는 말이야.","JPN":"その責任感に君が押しつぶされそうだから言っているんだ。","ENG":"That sense of responsibility is crushing you.","TWN":"我說這些是因為我感覺到那份責任感正在壓垮你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"스스로를 희생하면서까지 모든 걸 짊어질 필요는…….","JPN":"自分を犠牲にしてまですべてを背負う必要は……","ENG":"You don't have to sacrifice yourself by carrying everything by yourself...","TWN":"沒有必要為了犧牲自己而承擔一切……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"희생이라니. 섭섭한 말씀을 하시네요.","JPN":"犠牲だなんて、寂しいことをおっしゃるのね。","ENG":"\\"Sacrifice\\"? That's a bit harsh.","TWN":"犧牲什麼的，你這就讓人傷心了呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_31"},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는…… 이 세계가 좋아요, 알렌.","JPN":"私は……この世界が好きなのです、アレン。","ENG":"I just... I love this world, Allen.","TWN":"艾倫，我喜歡這個世界。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_32"},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세상이 어둠에 잠겼을지언정 서로가 서로를 의지하고.","JPN":"世界が闇に呑まれるとしても、お互いを頼り。","ENG":"Even in darkness, people still reach for each other.","TWN":"即使世界陷入黑暗，我們也要互相依靠。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_33"},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부족하게나마 내일을 맞이하기 위해 희망이라는 단어를 비추려 노력하는.","JPN":"微力ながらも、明日を迎えるために希望を照らそうと努力する。","ENG":"They try, however clumsily, to greet tomorrow with hope.","TWN":"儘管微不足道，但仍努力讓希望之光照亮明天。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_34"},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리고… 소중한 사람들이 곁에 있어주는 이곳이 좋습니다.","JPN":"そして……大切な人々がそばにいてくれるここが、好きです。","ENG":"And... I love this place where those dear to me are close by.","TWN":"而且……我喜歡有珍貴的人陪伴在身邊的這個地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_35"},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"좋아하는 걸 지키기 위해 제 한 몸 불사르는 것을 어찌 희생이라 할 수 있겠나요.","JPN":"好きなものを守るために自分の体を張ることを犠牲とは言えません。","ENG":"If I burn myself up to protect the things I love, how could that ever be called sacrifice?","TWN":"為了守護我所愛的東西，獻出我的生命又怎能稱為犧牲呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_36"},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는-","JPN":"私は……","ENG":"I–","TWN":"我-"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_37"},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……그래. 당신이라면 그렇겠지.","JPN":"……ああ。君ならそうだろう。","ENG":"...Yes. That's exactly the kind of person you are.","TWN":"……是嗎。你就是這樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 힘든 일이 있다면 언제든지 내게 기대게.","JPN":"だが、辛いことがあったらいつでも私に頼ってくれ。","ENG":"But if things get hard, lean on me. Anytime.","TWN":"但是如果有困難的話，隨時可以依靠我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 그건 전쟁이 끝난 이후로 미뤄두겠습니다.","JPN":"ふふ。それは戦争後にお預けですね。","ENG":"Haha. I'll save that for after the war.","TWN":"呵呵，那就等戰爭結束後再說吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"가정이 화목해지려면 역시 남편이 힘을 써줘야 하는 법이니까요.","JPN":"一家団欒のためには夫が頑張らなくてはいけないものですから。","ENG":"In a happy home, the husband's the one who has to put in the real effort.","TWN":"為了讓家庭和睦，還是需要丈夫多努力才行啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……이르군. 벌써 거기까지 생각해둔 건가?","JPN":"……早いな。もうそこまで考えているのか？","ENG":"...Wow. You're already thinking that far ahead?","TWN":"……太早了。已經想到那一步了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 장차 태어날 아이에게 붙여줄 이름까지 생각해 뒀답니다?","JPN":"あら。生まれる子どもの名前まで考えておいたのですよ？","ENG":"Oh? Why, I've even picked out names for our future children.","TWN":"哎呀。連將來要出生的孩子的名字都想好了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"만약 자식이 생긴다면, 이름은…….","JPN":"もし子どもができたら、名前は……","ENG":"If we ever do have children, I'd name them...","TWN":"如果有了孩子，名字就叫……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"제법 생각에 몰두하는군. 인도자라도 고민되는 일이 있는 건가?","JPN":"思いに耽るか。導き手といえど悩みはあるということか？","ENG":"She's really deep in thought. So even the Star Guide has things to worry about?","TWN":"看來你陷入了沉思。即使是引導者也有煩惱嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"글쎄요. 적어도 당신에게 말할 내용은 아닌 것 같군요.","JPN":"どうでしょう。少なくとも貴方に話すようなことではありません。","ENG":"Hmm. I doubt this is something I should be discussing with you.","TWN":"這個嘛，至少我覺得不該告訴你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여긴 당신이 있을 곳도 아니고요.","JPN":"ましてや、ここは貴方がいていい場所ではありません。","ENG":"And this isn't a place where you belong.","TWN":"這裡不是你該待的地方。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"번거롭게 입을 놀릴 필요는 없다. 어차피 네 알량한 고민 따위 뻔하니까.","JPN":"煩わしく口に出すまでもない。どうせお前のちっぽけな悩みなど目に見えている。","ENG":"No need for your petty words. I already know what you're worried about.","TWN":"沒必要費口舌。反正你的那些小煩惱我都知道。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이리 무리하게 힘의 계승을 시도하려 한 걸 보면 어지간히 급했던 모양이군, 인도자.","JPN":"ここまで無理やり力を継承しようとしていることを見ると、随分焦っていたようだな。導き手。","ENG":"Trying to force a succession of power like this, you must be desperate, Star Guide.","TWN":"看來你是相當急迫，才會如此勉強地嘗試力量的繼承吧，引導者。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하긴. 네 존재의 근원이었던 차원이 완전히 소실되었으니 더는 시간이 없었겠지.","JPN":"それもそうか。お前の存在の根源であった次元が完全に消失したのだ。もう時間がなかったのだろう。","ENG":"I suppose it makes sense. The dimension that birthed you has been completely erased. You're out of time.","TWN":"是啊。畢竟你存在的根源所在的次元已經徹底消失了，時間已經不多了吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"때문에 네놈의 과거를 답습시켜 그 애송이에게 인도자로서의 숙명을 넘기려 했던 모양이지만…….","JPN":"お前の過去をなぞらせ、あの小娘に導き手としての宿命を託そうとしていたようだが……","ENG":"So you tried to pass on your destiny by recreating your past and giving that burden to that kid...","TWN":"因此，似乎想要讓那個小丫頭重蹈你的覆轍，並將引導者的宿命傳給她……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"어설프군. 그 준비가 미약했던 탓에 간단히 개입할 수 있었다.","JPN":"ぬるいな。その準備が甘かったから、簡単に介入できた。","ENG":"But you were sloppy. That made it easy for me to interfere.","TWN":"真是拙劣。由於準備不足，我才能輕易介入。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그녀석이 지닌 운명의 일부. 처녀자리의 힘을 흡수한 마창이라면 진즉 확보했으니 말이야.","JPN":"やつが持っている運命の一部。乙女座の力を吸収した魔槍なら、すでに確保している。","ENG":"I have already secured the power of Virgo. Absorbed into the cursed spear that carries her fate.","TWN":"那傢伙所擁有的命運的一部分。若是吸收了處女座力量的魔槍，這部分我早已知情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"덕분에 그 알량한 녀석으로부터 인도자의 별빛을 빼앗기가 한결 수월해졌군.","JPN":"やつが未熟なおかげで、導き手の星の光を簡単に奪えそうだ。","ENG":"Thanks to that, stealing your starlight from her became much easier.","TWN":"多虧了你，從那個微不足道的傢伙那裡奪取引導者的星光變得容易多了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자신의 바람대로 이루어질 것이라는 생각이 실로 오만하군요.","JPN":"自分の望みどおりになるという考え方、実に傲慢ですね。","ENG":"You're awfully arrogant, assuming things will go as you wish.","TWN":"認為事情會如自己所願，實在是太傲慢了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제가 그것을 용인할 것 같습니까?","JPN":"私がそれを許すとでも？","ENG":"Do you really think I'll allow that?","TWN":"你覺得我會容忍那種事情嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"너저분한 연출은 관두지, 인도자. 네놈의 그 알량한 신념은 고향을 멸망시키는데 일조하지 않았나?","JPN":"くどい演出はやめろ、導き手。貴様のくだらない信念は、故郷の滅亡に一役かっていただろう。","ENG":"Enough with the theatrics, Guide. Your flimsy ideals helped destroy your homeland, didn't they?","TWN":"別再搞那些亂七八糟的了，引導者。你的那點可笑的信念不也助長了故鄉的毀滅嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과거를 답습하다 피로 얼룩진 최후를 맞았던 네가 같은 선택을 반복하리라고는 생각되지 않는군.","JPN":"過去をなぞって、血まみれとなった最期を迎えた貴様が同じ選択を繰り返すとは思えない。","ENG":"I don't believe someone who died bloodied by repeating their past mistakes would do it again.","TWN":"重蹈覆轍，迎來血染的結局，我不認為你會重複同樣的選擇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"속이 뒤틀릴 것 같으니 그 얼굴로 더러운 입을 놀리지 마시지요.","JPN":"吐き気がしますので、その顔で汚い口をきかないで欲しいわ。","ENG":"Your twisted face and words are making me nauseous.","TWN":"我要反胃了，請別用那張臉說些骯髒的話。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무구를 힘으로써 여기는 당신은 그 가치를 결코 이해할 수 없습니다.","JPN":"武具を力と思っている貴方には、決してその価値は理解できないはずです。","ENG":"One who sees a weapon as nothing more than power can never understand its true worth.","TWN":"將武具視為力量的你，永遠無法理解它的真正價值。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 기사단에서 무구의 가치를 온전히 이해하고 있는 것은 오직 나뿐이다.","JPN":"いや、騎士団で武具の価値を完全に理解しているのは俺だけだ。","ENG":"No. I'm the only one in the Order who truly understands their worth.","TWN":"不，騎士團中只有我完全理解武具的價值。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈도 알고 있을 텐데? 결국 숭고한 희생 따위 힘 앞에서는 어떤 가치도 없다는 걸.","JPN":"貴様も知っているはずだ。結局崇高な犠牲など、力の前には無価値だということを。","ENG":"You know it too, don't you? In the end, noble sacrifice means nothing before raw power.","TWN":"你應該也知道吧？最終，所謂崇高的犧牲在力量面前毫無價值。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……당신. 지금 제 동료들의 죽음을 모욕하는 겁니까?","JPN":"……貴方。今、私の仲間の死を侮辱しているのですか？","ENG":"...Are you mocking the deaths of my comrades?","TWN":"……你。是在侮辱我同伴的死嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하. 세계를 멸망시키려 한 족속들이 퍽이나 명예롭겠군.","JPN":"は。世界を滅亡させようとした輩に名誉などあるものか。","ENG":"Hah. As if those who tried to destroy the world have anything noble left in them.","TWN":"哈。那些試圖毀滅世界的傢伙真是光榮啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그렇게까지 한심한 결말을 보고 싶다면 말리지는 않겠다만…….","JPN":"そこまで情けない結末を迎えたいのなら止めはしないが……","ENG":"But if you really want to see it through to such a pathetic end, I won't stop you...","TWN":"如果你想看到如此可悲的結局，我不會阻止你……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"육체와 영혼을 다하면서까지 이루고자 한 네 소임이 무엇이었는지 잘 생각해보도록.","JPN":"肉体と魂が尽きるまで果たそうとしていたお前の役目とは何だったのか、よく考えてみることだ。","ENG":"Just make sure you remember what you strived for, even at the cost of your body and soul.","TWN":"好好想想你拼盡全力想要完成的使命是什麼。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"무력함에 휩싸여 기사단을 빠져나온 그 애송이가, 네가 부여한 숙명을 버텨낼 수 있을지도 말이야.","JPN":"無力さに絶望し騎士団から逃げたあの小娘が、お前が与えた宿命に耐えられるのかも。","ENG":"I wonder if that kid who left the Order drowning in helplessness can really endure the fate that you've placed upon.","TWN":"被無力感包圍而離開騎士團的那個小子，是否能承受你賦予的宿命呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"유감스러우나 그것에 관해서라면 당신이 태어나기 전부터 고민해왔습니다.","JPN":"残念ですが、それについてなら貴方が生まれる前から悩んできました。","ENG":"You'll be disappointed to hear I've wrestled with that question since before you were born.","TWN":"很遺憾，這方面我在你出生之前就已經考慮過了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니, 이만 사라지세요. 더 이상 당신과 나눌 이야기는 없습니다.","JPN":"ですので、もう消えてください。これ以上貴方と交わす言葉などありません。","ENG":"So leave. We've nothing more to discuss.","TWN":"所以，到此為止吧。沒有什麼好再和你說的了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"자신의 숙명으로부터 벗어나기 위해 네놈도 누군가에게 그 업을 떠넘기려 했을 텐데?","JPN":"自分の宿命から逃げるため、そなたもまた誰かにその業を押しつけようとしたはずだが。","ENG":"Surely you too tried to cast off your fate by passing your burden onto someone else?","TWN":"為了擺脫自己的宿命，你也曾試圖將這份業障轉嫁給別人吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L42_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네놈과 나는 다르지 않다.","JPN":"そなたと我は同じだ。","ENG":"You and I are no different.","TWN":"我和你沒有什麼不同。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그저 선악을 구분하는 경계선에 달리 있을 뿐.","JPN":"ただ善悪を区別する境界線の向こう側にいるだけ。","ENG":"We just stand on opposite sides of a fading line.","TWN":"只不過是在區分善惡的界限上奔跑而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"너저분한 연출은 관두지, 인도자. 네놈의 그 알량한 신념은 고향을 멸망시키는데 일조하지 않았나?","JPN":"くどい演出はやめろ、導き手。貴様のくだらない信念は、故郷の滅亡に一役かっていただろう。","ENG":"Enough with the theatrics, Guide. Your flimsy ideals helped destroy your homeland, didn't they?","TWN":"別再搞那些亂七八糟的了，引導者。你的那點可笑的信念不也助長了故鄉的毀滅嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L45_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과거를 답습하다 피로 얼룩진 최후를 맞았던 네가 같은 선택을 반복하리라고는 생각되지 않는군.","JPN":"過去をなぞって、血まみれとなった最期を迎えた貴様が同じ選択を繰り返すとは思えない。","ENG":"I don't believe someone who died bloodied by repeating their past mistakes would do it again.","TWN":"重蹈覆轍，迎來血染的結局，我不認為你會重複同樣的選擇。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……そう。","ENG":"...You're right.","TWN":"……是啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이것이 내가 짊어져야 하는 업이라면…….","JPN":"これが私の背負うべき業なら……","ENG":"If this is the burden I must carry...","TWN":"如果這是我必須背負的業障……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마지막까지 책임을 져야겠지.","JPN":"最後まで責任を取らないと。","ENG":"Then I will see it through until the end.","TWN":"我會負責到底。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};